class Playground {
    async run(inputs) {
        const nums = inputs[0].split(',').map(Number);
        const k = parseInt(inputs[1]);

        // 1. Initialize Visualizations
        await this.numsArray.init(nums);
        // We initialize the map with {0: 1} to handle cases where (currentSum === k)
        await this.prefixSumMap.init([[0, 1]]);
        await this.state.init([
            ["count", 0],
            ["currentSum", 0],
            ["targetToFind", "-"]
        ]);

        this.log("Initialized map with {0: 1} to account for subarrays starting from index 0.");
        await this.await();

        let count = 0;
        let currentSum = 0;

        for (let i = 0; i < nums.length; i++) {
            // Reset highlights and focus on current element
            this.numsArray.highlight(i, "#00e0ff");
            currentSum += nums[i];

            const targetToFind = currentSum - k;

            this.state.put("currentSum", currentSum);
            this.state.put("targetToFind", targetToFind);
            this.state.highlight("targetToFind", "#ffb703");

            this.log(`Index ${i}: val=${nums[i]}, sum=${currentSum}. Looking for prefix sum (sum - k) = ${targetToFind}`);
            await this.await();

            // Check if the target prefix sum exists in our map
            if (this.prefixSumMap.has(targetToFind)) {
                const frequency = this.prefixSumMap.get(targetToFind);
                count += frequency;

                this.prefixSumMap.highlight(targetToFind, "#00f5a0");
                this.state.put("count", count);
                this.state.highlight("count", "#00f5a0");

                this.log(`Found! Prefix sum ${targetToFind} occurred ${frequency} time(s). Total subarrays updated to ${count}.`);
                await this.await();
            } else {
                this.log(`Prefix sum ${targetToFind} not found in map.`);
                await this.await();
            }

            // Update the frequency of the current prefix sum in the map
            const currentFreq = this.prefixSumMap.has(currentSum) ? this.prefixSumMap.get(currentSum) : 0;
            this.prefixSumMap.put(currentSum, currentFreq + 1);
            this.prefixSumMap.highlight(currentSum, "#6c8cff");

            this.log(`Updated map: freq of sum ${currentSum} is now ${currentFreq + 1}`);
            await this.await();

            // Clean up highlights for next iteration
            this.numsArray.highlight(i, null);
            this.prefixSumMap.highlight(targetToFind, null);
            this.prefixSumMap.highlight(currentSum, null);
            this.state.highlight("count", null);
            this.state.highlight("targetToFind", null);
        }

        this.log(`Finished! Total subarrays with sum ${k} is ${count}`);
        return count;
    }
}
